// Package report builds standalone HTML evidence packages from cases.
//
// Output is a single self-contained .html file with every event, alert, and
// annotation embedded inline (no external assets, no JS), plus a deterministic
// narrative paragraph generated by templated rules over the timeline. PDF
// rendering is deferred to whatever the operator already runs (browser
// "save as PDF" works fine on a self-contained HTML file).
//
// "Deterministic, no AI" is non-negotiable per the Phase 38 spec: the same
// case at the same audit-root must produce byte-identical output forever, so
// the narrative builder uses a small set of conditional template snippets
// keyed off counts and severities — no LLM, no randomness.
package report

import (
	"bytes"
	"fmt"
	"html/template"
	"sort"
	"strings"
	"time"
)

// To avoid an import cycle (services imports report from report_service.go;
// report would otherwise import services), we redefine flat structs here.
// services maps Case → report.CaseInfo at the boundary.

type Hypothesis struct {
	ID         string    `json:"id"`
	Statement  string    `json:"statement"`
	Status     string    `json:"status"`
	CreatedBy  string    `json:"createdBy"`
	CreatedAt  time.Time `json:"createdAt"`
	UpdatedAt  time.Time `json:"updatedAt"`
}

type Annotation struct {
	EventID   string    `json:"eventId"`
	Body      string    `json:"body"`
	Author    string    `json:"author"`
	Timestamp time.Time `json:"timestamp"`
}

type CaseInfo struct {
	ID, Title       string
	OpenedBy        string
	OpenedAt        time.Time
	State           string
	HostID          string
	From, To        time.Time
	AuditRootAtOpen string
	SealedBy        string
	SealedAt        time.Time
	Hypotheses      []Hypothesis
	Annotations     []Annotation
}

type TimelineEntry struct {
	Kind      string
	Timestamp time.Time
	Severity  string
	Title     string
	Detail    string
	RefID     string
}

type ConfidenceInfo struct {
	Score       int
	Explanation string
}

type Package struct {
	Case        CaseInfo
	Timeline    []TimelineEntry
	Confidence  *ConfidenceInfo
	AuditRoot   string
	GeneratedAt time.Time
	Verifier    string
}

// Render returns a fully-inlined HTML document.
func Render(p Package) ([]byte, error) {
	tpl, err := template.New("evidence").Funcs(template.FuncMap{
		"narrative": func() string { return Narrative(p) },
		"time":      func(t time.Time) string { return t.UTC().Format(time.RFC3339) },
		"sev":       sevColorClass,
	}).Parse(htmlTemplate)
	if err != nil {
		return nil, err
	}
	var buf bytes.Buffer
	if err := tpl.Execute(&buf, p); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

// Narrative produces a deterministic paragraph summarising the case.
func Narrative(p Package) string {
	c := p.Case
	var b strings.Builder

	fmt.Fprintf(&b, "Investigation \"%s\" was opened by %s at %s and ", c.Title, c.OpenedBy, c.OpenedAt.UTC().Format(time.RFC3339))
	switch c.State {
	case "sealed":
		fmt.Fprintf(&b, "sealed by %s at %s. ", c.SealedBy, c.SealedAt.UTC().Format(time.RFC3339))
	default:
		b.WriteString("remains open. ")
	}
	if c.HostID != "" {
		fmt.Fprintf(&b, "Scope is host %s ", c.HostID)
	} else {
		b.WriteString("Scope spans every host ")
	}
	fmt.Fprintf(&b, "between %s and %s. ", c.From.UTC().Format(time.RFC3339), c.To.UTC().Format(time.RFC3339))

	// Tally kinds.
	kinds := map[string]int{}
	severeAlerts := 0
	for _, t := range p.Timeline {
		kinds[t.Kind]++
		if t.Kind == "alert" && (t.Severity == "high" || t.Severity == "critical") {
			severeAlerts++
		}
	}
	fmt.Fprintf(&b, "The frozen snapshot contains %d events, %d alerts, %d log gaps, and %d sealed evidence packages. ",
		kinds["event"], kinds["alert"], kinds["gap"], kinds["evidence"])
	if severeAlerts > 0 {
		fmt.Fprintf(&b, "Of the alerts, %d were severity high or critical. ", severeAlerts)
	}
	if p.Confidence != nil {
		fmt.Fprintf(&b, "Forensic confidence: %d%% — %s. ", p.Confidence.Score, p.Confidence.Explanation)
	}
	if c.AuditRootAtOpen != "" {
		fmt.Fprintf(&b, "Audit chain root at case open: %s. ", c.AuditRootAtOpen)
	}
	if p.Verifier != "" {
		fmt.Fprintf(&b, "Verification: run `%s` against the accompanying audit.log to confirm chain integrity. ", p.Verifier)
	}

	// Confirmed hypotheses, in declaration order.
	confirmed := []Hypothesis{}
	for _, h := range c.Hypotheses {
		if h.Status == "confirmed" {
			confirmed = append(confirmed, h)
		}
	}
	if len(confirmed) > 0 {
		sort.Slice(confirmed, func(i, j int) bool { return confirmed[i].CreatedAt.Before(confirmed[j].CreatedAt) })
		b.WriteString("Confirmed hypotheses: ")
		for i, h := range confirmed {
			if i > 0 {
				b.WriteString("; ")
			}
			b.WriteString(`"` + h.Statement + `"`)
		}
		b.WriteString(".")
	}
	return b.String()
}

func sevColorClass(s string) string {
	switch s {
	case "critical", "alert":
		return "sev-critical"
	case "error":
		return "sev-error"
	case "warning", "high":
		return "sev-warn"
	default:
		return "sev-info"
	}
}

const htmlTemplate = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>OBLIVRA Evidence Package — {{.Case.Title}}</title>
<style>
body { font-family: -apple-system, system-ui, "Segoe UI", sans-serif; max-width: 920px; margin: 32px auto; color: #111; }
h1, h2, h3 { color: #0d2c4a; }
.sev-critical { color: #b00020; font-weight: bold; }
.sev-error { color: #b00020; }
.sev-warn { color: #b07000; }
.sev-info { color: #335; }
table { border-collapse: collapse; width: 100%; margin: 8px 0; font-size: 12px; }
td, th { border: 1px solid #ddd; padding: 4px 6px; text-align: left; vertical-align: top; }
tr:nth-child(even) { background: #fafafa; }
code { background: #f3f3f3; padding: 1px 4px; border-radius: 2px; font-size: 11px; }
.meta { font-size: 11px; color: #555; margin: 4px 0; }
.hash { font-family: ui-monospace, monospace; font-size: 10px; word-break: break-all; }
.narrative { background: #f6f9ff; padding: 16px; border-left: 4px solid #335; }
</style>
</head>
<body>
<h1>OBLIVRA Evidence Package</h1>
<div class="meta">Generated at {{time .GeneratedAt}}</div>

<h2>Case: {{.Case.Title}}</h2>
<table>
<tr><th>ID</th><td><code>{{.Case.ID}}</code></td></tr>
<tr><th>Opened by</th><td>{{.Case.OpenedBy}}</td></tr>
<tr><th>Opened at</th><td>{{time .Case.OpenedAt}}</td></tr>
<tr><th>State</th><td>{{.Case.State}}</td></tr>
<tr><th>Scope host</th><td>{{.Case.HostID}}</td></tr>
<tr><th>Scope from</th><td>{{time .Case.From}}</td></tr>
<tr><th>Scope to</th><td>{{time .Case.To}}</td></tr>
<tr><th>Audit root @ open</th><td class="hash">{{.Case.AuditRootAtOpen}}</td></tr>
{{if .Case.SealedAt.IsZero}}{{else}}
<tr><th>Sealed by</th><td>{{.Case.SealedBy}} at {{time .Case.SealedAt}}</td></tr>
{{end}}
</table>

<h2>Narrative</h2>
<div class="narrative">{{narrative}}</div>

{{if .Case.Hypotheses}}
<h2>Hypotheses</h2>
<table><tr><th>Statement</th><th>Status</th><th>Created by</th><th>Updated</th></tr>
{{range .Case.Hypotheses}}
<tr><td>{{.Statement}}</td><td>{{.Status}}</td><td>{{.CreatedBy}}</td><td>{{time .UpdatedAt}}</td></tr>
{{end}}
</table>
{{end}}

{{if .Case.Annotations}}
<h2>Annotations</h2>
<table><tr><th>Event</th><th>Author</th><th>Note</th></tr>
{{range .Case.Annotations}}
<tr><td><code>{{.EventID}}</code></td><td>{{.Author}}</td><td>{{.Body}}</td></tr>
{{end}}
</table>
{{end}}

<h2>Timeline ({{len .Timeline}} entries)</h2>
<table><tr><th>When (UTC)</th><th>Kind</th><th>Severity</th><th>Title</th><th>Detail</th></tr>
{{range .Timeline}}
<tr>
  <td>{{time .Timestamp}}</td>
  <td>{{.Kind}}</td>
  <td class="{{sev .Severity}}">{{.Severity}}</td>
  <td>{{.Title}}</td>
  <td>{{.Detail}}</td>
</tr>
{{end}}
</table>

<h2>Verification instructions</h2>
<p>To confirm this package was not altered after generation:</p>
<ol>
<li>Copy the host's <code>audit.log</code> into the same directory as this file.</li>
<li>Run <code>{{.Verifier}}</code>.</li>
<li>Confirm the printed root hash matches <span class="hash">{{.AuditRoot}}</span>.</li>
</ol>
<p class="meta">Audit root at generation time: <span class="hash">{{.AuditRoot}}</span></p>
</body>
</html>`
